// ==================== Security Manager ====================

class PaymentSecurityManager {
  static final PaymentSecurityManager _instance =
      PaymentSecurityManager._internal();
  factory PaymentSecurityManager() => _instance;
  PaymentSecurityManager._internal();

  String _encryptionKey = '';
  String _apiKey = '';
  bool _isProduction = false;

  void initialize({
    required String encryptionKey,
    required String apiKey,
    bool isProduction = false,
  }) {
    _encryptionKey = encryptionKey;
    _apiKey = apiKey;
    _isProduction = isProduction;
  }

  String generateTransactionId() {
    final timestamp = DateTime.now().millisecondsSinceEpoch;
    final random = List.generate(16, (i) => timestamp.hashCode + i);
    return base64Url.encode(random).substring(0, 32);
  }

  String generateSignature(Map<String, dynamic> data) {
    final sortedKeys = data.keys.toList()..sort();
    final signatureString =
        sortedKeys.map((key) => '$key=${data[key]}').join('&');
    final bytes = utf8.encode(signatureString + _encryptionKey);
    final digest = sha256.convert(bytes);
    return digest.toString();
  }

  bool verifySignature(Map<String, dynamic> data, String signature) {
    final calculatedSignature = generateSignature(data);
    return calculatedSignature == signature;
  }

  String encryptSensitiveData(String data) {
    final bytes = utf8.encode(data);
    final key = utf8.encode(_encryptionKey.padRight(32).substring(0, 32));
    final encrypted = <int>[];

    for (int i = 0; i < bytes.length; i++) {
      encrypted.add(bytes[i] ^ key[i % key.length]);
    }

    return base64Url.encode(encrypted);
  }

  String decryptSensitiveData(String encryptedData) {
    final encrypted = base64Url.decode(encryptedData);
    final key = utf8.encode(_encryptionKey.padRight(32).substring(0, 32));
    final decrypted = <int>[];

    for (int i = 0; i < encrypted.length; i++) {
      decrypted.add(encrypted[i] ^ key[i % key.length]);
    }

    return utf8.decode(decrypted);
  }

  Map<String, String> getSecureHeaders() {
    return {
      'Content-Type': 'application/json',
      'X-API-Key': _apiKey,
      'X-Platform': Platform.isIOS ? 'ios' : 'android',
      'X-Timestamp': DateTime.now().millisecondsSinceEpoch.toString(),
    };
  }

  bool validateAmount(double amount) {
    return amount > 0 && amount < 1000000;
  }

  bool validateCurrency(String currency) {
    const validCurrencies = ['USD', 'EUR', 'GBP', 'JPY', 'AUD', 'CAD'];
    return validCurrencies.contains(currency.toUpperCase());
  }

  String sanitizeInput(String input) {
    return input.replaceAll(RegExp(r'[^\w\s\-\.]'), '');
  }
}

