class InAppPurchaseHandler {
  static const MethodChannel _channel =
      MethodChannel('com.payment.iap/channel');

  final StreamController<PaymentTransaction> _purchaseController =
      StreamController<PaymentTransaction>.broadcast();
  Stream<PaymentTransaction> get purchaseStream => _purchaseController.stream;

  final Map<String, Product> _products = {};
  bool _isInitialized = false;

  Future<void> initialize() async {
    if (_isInitialized) return;

    try {
      _channel.setMethodCallHandler(_handleMethodCall);
      await _channel.invokeMethod('initialize');
      _isInitialized = true;
    } catch (e) {
      throw Exception('Failed to initialize IAP: $e');
    }
  }

  Future<void> _handleMethodCall(MethodCall call) async {
    switch (call.method) {
      case 'onPurchaseUpdate':
        final data = Map<String, dynamic>.from(call.arguments);
        final transaction = PaymentTransaction.fromJson(data);
        _purchaseController.add(transaction);
        break;
      case 'onPurchaseError':
        final error = call.arguments as String;
        debugPrint('Purchase error: $error');
        break;
    }
  }

  Future<List<Product>> fetchProducts(List<String> productIds) async {
    try {
      final result = await _channel.invokeMethod('fetchProducts', {
        'productIds': productIds,
      });

      final products = (result as List)
          .map((p) => Product.fromJson(Map<String, dynamic>.from(p)))
          .toList();

      for (var product in products) {
        _products[product.id] = product;
      }

      return products;
    } catch (e) {
      throw Exception('Failed to fetch products: $e');
    }
  }

  Future<PaymentResult> purchaseProduct(String productId, String userId) async {
    if (!_isInitialized) {
      return PaymentResult.failure('IAP not initialized');
    }

    final product = _products[productId];
    if (product == null) {
      return PaymentResult.failure('Product not found');
    }

    try {
      final transactionId = PaymentSecurityManager().generateTransactionId();

      final result = await _channel.invokeMethod('purchase', {
        'productId': productId,
        'userId': userId,
        'transactionId': transactionId,
      });

      if (result['success'] == true) {
        final transaction = PaymentTransaction(
          id: transactionId,
          userId: userId,
          amount: product.price,
          currency: product.currency,
          method: PaymentMethod.inAppPurchase,
          type: product.isSubscription
              ? TransactionType.subscription
              : TransactionType.purchase,
          status: PaymentStatus.completed,
          timestamp: DateTime.now(),
          receiptData: result['receipt'],
          metadata: {'productId': productId},
        );

        return PaymentResult.success(transaction);
      } else {
        return PaymentResult.failure(
          result['error'] ?? 'Purchase failed',
          code: result['errorCode'],
        );
      }
    } catch (e) {
      return PaymentResult.failure('Purchase error: $e');
    }
  }

  Future<bool> restorePurchases(String userId) async {
    try {
      final result = await _channel.invokeMethod('restorePurchases', {
        'userId': userId,
      });

      return result['success'] == true;
    } catch (e) {
      debugPrint('Restore purchases error: $e');
      return false;
    }
  }

  Future<bool> finishTransaction(String transactionId) async {
    try {
      await _channel.invokeMethod('finishTransaction', {
        'transactionId': transactionId,
      });
      return true;
    } catch (e) {
      debugPrint('Finish transaction error: $e');
      return false;
    }
  }

  void dispose() {
    _purchaseController.close();
  }
}

