class ApplePayHandler {
  static const MethodChannel _channel =
      MethodChannel('com.payment.applepay/channel');

  Future<bool> isAvailable() async {
    if (!Platform.isIOS) return false;

    try {
      final result = await _channel.invokeMethod('isAvailable');
      return result == true;
    } catch (e) {
      return false;
    }
  }

  Future<PaymentResult> processPayment({
    required String userId,
    required double amount,
    required String currency,
    required String merchantId,
    required String description,
  }) async {
    if (!await isAvailable()) {
      return PaymentResult.failure('Apple Pay not available');
    }

    final security = PaymentSecurityManager();
    if (!security.validateAmount(amount) ||
        !security.validateCurrency(currency)) {
      return PaymentResult.failure('Invalid amount or currency');
    }

    try {
      final transactionId = security.generateTransactionId();

      final result = await _channel.invokeMethod('processPayment', {
        'transactionId': transactionId,
        'amount': amount,
        'currency': currency,
        'merchantId': merchantId,
        'description': description,
      });

      if (result['success'] == true) {
        final transaction = PaymentTransaction(
          id: transactionId,
          userId: userId,
          amount: amount,
          currency: currency,
          method: PaymentMethod.applePay,
          type: TransactionType.purchase,
          status: PaymentStatus.completed,
          timestamp: DateTime.now(),
          receiptData: result['token'],
          metadata: {'description': description},
        );

        return PaymentResult.success(transaction);
      } else {
        return PaymentResult.failure(
          result['error'] ?? 'Payment failed',
          code: result['errorCode'],
        );
      }
    } catch (e) {
      return PaymentResult.failure('Apple Pay error: $e');
    }
  }
}

