// ==================== Stripe Payment Gateway ====================

class StripePaymentGateway {
  final String _publishableKey;
  final String _secretKey;
  final String _baseUrl = 'https://api.stripe.com/v1';

  StripePaymentGateway({
    required String publishableKey,
    required String secretKey,
  })  : _publishableKey = publishableKey,
        _secretKey = secretKey;

  Future<PaymentResult> createPaymentIntent({
    required String userId,
    required double amount,
    required String currency,
    Map<String, dynamic>? metadata,
  }) async {
    final security = PaymentSecurityManager();
    if (!security.validateAmount(amount) ||
        !security.validateCurrency(currency)) {
      return PaymentResult.failure('Invalid amount or currency');
    }

    try {
      final transactionId = security.generateTransactionId();
      final amountInCents = (amount * 100).toInt();

      final response = await http.post(
        Uri.parse('$_baseUrl/payment_intents'),
        headers: {
          'Authorization': 'Bearer $_secretKey',
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: {
          'amount': amountInCents.toString(),
          'currency': currency.toLowerCase(),
          'metadata[transactionId]': transactionId,
          'metadata[userId]': userId,
          if (metadata != null)
            ...metadata.map((key, value) => MapEntry('metadata[$key]', value.toString())),
        },
      );

      if (response.statusCode == 200) {
        final data = json.decode(response.body);

        final transaction = PaymentTransaction(
          id: transactionId,
          userId: userId,
          amount: amount,
          currency: currency,
          method: PaymentMethod.stripe,
          type: TransactionType.purchase,
          status: PaymentStatus.pending,
          timestamp: DateTime.now(),
          metadata: {
            'paymentIntentId': data['id'],
            'clientSecret': data['client_secret'],
            ...?metadata,
          },
        );

        return PaymentResult.success(transaction);
      } else {
        final error = json.decode(response.body);
        return PaymentResult.failure(
          error['error']['message'] ?? 'Payment intent creation failed',
          code: error['error']['code'],
        );
      }
    } catch (e) {
      return PaymentResult.failure('Stripe error: $e');
    }
  }

  Future<PaymentResult> confirmPayment({
    required String paymentIntentId,
    required String paymentMethodId,
  }) async {
    try {
      final response = await http.post(
        Uri.parse('$_baseUrl/payment_intents/$paymentIntentId/confirm'),
        headers: {
          'Authorization': 'Bearer $_secretKey',
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: {
          'payment_method': paymentMethodId,
        },
      );

      if (response.statusCode == 200) {
        final data = json.decode(response.body);
        final status = data['status'];

        PaymentStatus paymentStatus;
        if (status == 'succeeded') {
          paymentStatus = PaymentStatus.completed;
        } else if (status == 'processing') {
          paymentStatus = PaymentStatus.processing;
        } else {
          paymentStatus = PaymentStatus.failed;
        }

        final transaction = PaymentTransaction(
          id: data['metadata']['transactionId'],
          userId: data['metadata']['userId'],
          amount: data['amount'] / 100.0,
          currency: data['currency'].toUpperCase(),
          method: PaymentMethod.stripe,
          type: TransactionType.purchase,
          status: paymentStatus,
          timestamp: DateTime.now(),
          metadata: {
            'paymentIntentId': data['id'],
            'stripeStatus': status,
          },
        );

        return PaymentResult.success(transaction);
      } else {
        final error = json.decode(response.body);
        return PaymentResult.failure(
          error['error']['message'] ?? 'Payment confirmation failed',
          code: error['error']['code'],
        );
      }
    } catch (e) {
      return PaymentResult.failure('Stripe confirmation error: $e');
    }
  }

  Future<PaymentResult> refundPayment({
    required String paymentIntentId,
    double? amount,
  }) async {
    try {
      final body = <String, String>{
        'payment_intent': paymentIntentId,
      };

      if (amount != null) {
        body['amount'] = (amount * 100).toInt().toString();
      }

      final response = await http.post(
        Uri.parse('$_baseUrl/refunds'),
        headers: {
          'Authorization': 'Bearer $_secretKey',
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: body,
      );

      if (response.statusCode == 200) {
        final data = json.decode(response.body);

        final transaction = PaymentTransaction(
          id: PaymentSecurityManager().generateTransactionId(),
          userId: '',
          amount: data['amount'] / 100.0,
          currency: data['currency'].toUpperCase(),
          method: PaymentMethod.stripe,
          type: TransactionType.refund,
          status: PaymentStatus.refunded,
          timestamp: DateTime.now(),
          metadata: {
            'refundId': data['id'],
            'paymentIntentId': paymentIntentId,
          },
        );

        return PaymentResult.success(transaction);
      } else {
        final error = json.decode(response.body);
        return PaymentResult.failure(
          error['error']['message'] ?? 'Refund failed',
          code: error['error']['code'],
        );
      }
    } catch (e) {
      return PaymentResult.failure('Refund error: $e');
    }
  }
}

// ==================== Payment Manager ====================

class PaymentManager {
  static final PaymentManager _instance = PaymentManager._internal();
  factory PaymentManager() => _instance;
  PaymentManager._internal();

  final InAppPurchaseHandler _iapHandler = InAppPurchaseHandler();
  final ApplePayHandler _applePayHandler = ApplePayHandler();
  final GooglePayHandler _googlePayHandler = GooglePayHandler();
  StripePaymentGateway? _stripeGateway;

  final StreamController<PaymentTransaction> _transactionController =
      StreamController<PaymentTransaction>.broadcast();
  Stream<PaymentTransaction> get transactionStream =>
      _transactionController.stream;

  final List<PaymentTransaction> _transactionHistory = [];
  List<PaymentTransaction> get transactionHistory =>
      List.unmodifiable(_transactionHistory);

  bool _isInitialized = false;

  Future<void> initialize({
    required String encryptionKey,
    required String apiKey,
    String? stripePublishableKey,
    String? stripeSecretKey,
    bool isProduction = false,
  }) async {
    if (_isInitialized) return;

    PaymentSecurityManager().initialize(
      encryptionKey: encryptionKey,
      apiKey: apiKey,
      isProduction: isProduction,
    );

    await _iapHandler.initialize();

    if (stripePublishableKey != null && stripeSecretKey != null) {
      _stripeGateway = StripePaymentGateway(
        publishableKey: stripePublishableKey,
        secretKey: stripeSecretKey,
      );
    }

    _iapHandler.purchaseStream.listen(_handleTransaction);

    _isInitialized = true;
  }

  void _handleTransaction(PaymentTransaction transaction) {
    _transactionHistory.add(transaction);
    _transactionController.add(transaction);
  }

  Future<List<Product>> fetchProducts(List<String> productIds) async {
    return await _iapHandler.fetchProducts(productIds);
  }

  Future<PaymentResult> processPayment({
    required String userId,
    required double amount,
    required String currency,
    required PaymentMethod method,
    String? productId,
    String? merchantId,
    String? description,
    Map<String, dynamic>? metadata,
  }) async {
    if (!_isInitialized) {
      return PaymentResult.failure('Payment manager not initialized');
    }

    PaymentResult result;

    switch (method) {
      case PaymentMethod.inAppPurchase:
        if (productId == null) {
          return PaymentResult.failure('Product ID required for IAP');
        }
        result = await _iapHandler.purchaseProduct(productId, userId);
        break;

      case PaymentMethod.applePay:
        if (merchantId == null) {
          return PaymentResult.failure('Merchant ID required for Apple Pay');
        }
        result = await _applePayHandler.processPayment(
          userId: userId,
          amount: amount,
          currency: currency,
          merchantId: merchantId,
          description: description ?? 'Payment',
        );
        break;

      case PaymentMethod.googlePay:
        if (merchantId == null) {
          return PaymentResult.failure('Merchant ID required for Google Pay');
        }
        result = await _googlePayHandler.processPayment(
          userId: userId,
          amount: amount,
          currency: currency,
          merchantId: merchantId,
          description: description ?? 'Payment',
        );
        break;

      case PaymentMethod.stripe:
        if (_stripeGateway == null) {
          return PaymentResult.failure('Stripe not configured');
        }
        result = await _stripeGateway!.createPaymentIntent(
          userId: userId,
          amount: amount,
          currency: currency,
          metadata: metadata,
        );
        break;

      default:
        return PaymentResult.failure('Payment method not supported');
    }

    if (result.success && result.transaction != null) {
      _handleTransaction(result.transaction!);
      await _verifyAndRecordTransaction(result.transaction!);
    }

    return result;
  }

  Future<void> _verifyAndRecordTransaction(
      PaymentTransaction transaction) async {
    try {
      final security = PaymentSecurityManager();
      final signature = security.generateSignature(transaction.toJson());

      final response = await http.post(
        Uri.parse('https://api.yourbackend.com/transactions/verify'),
        headers: security.getSecureHeaders(),
        body: json.encode({
          ...transaction.toJson(),
          'signature': signature,
        }),
      );

      if (response.statusCode != 200) {
        debugPrint('Transaction verification failed: ${response.body}');
      }
    } catch (e) {
      debugPrint('Transaction recording error: $e');
    }
  }

  Future<PaymentResult> refundTransaction(String transactionId) async {
    final transaction = _transactionHistory.firstWhere(
      (t) => t.id == transactionId,
      orElse: () => throw Exception('Transaction not found'),
    );

    if (transaction.method == PaymentMethod.stripe && _stripeGateway != null) {
      final paymentIntentId = transaction.metadata['paymentIntentId'];
      if (paymentIntentId != null) {
        return await _stripeGateway!.refundPayment(
          paymentIntentId: paymentIntentId,
        );
      }
    }

    return PaymentResult.failure('Refund not supported for this payment method');
  }

  Future<bool> restorePurchases(String userId) async {
    return await _iapHandler.restorePurchases(userId);
  }

  Future<bool> isPaymentMethodAvailable(PaymentMethod method) async {
    switch (method) {
      case PaymentMethod.applePay:
        return await _applePayHandler.isAvailable();
      case PaymentMethod.googlePay:
        return await _googlePayHandler.isAvailable();
      case PaymentMethod.stripe:
        return _stripeGateway != null;
      case PaymentMethod.inAppPurchase:
        return true;
      default:
        return false;
    }
  }

  List<PaymentTransaction> getTransactionsByUser(String userId) {
    return _transactionHistory.where((t) => t.userId == userId).toList();
  }

  List<PaymentTransaction> getTransactionsByStatus(PaymentStatus status) {
    return _transactionHistory.where((t) => t.status == status).toList();
  }

  PaymentTransaction? getTransactionById(String transactionId) {
    try {
      return _transactionHistory.firstWhere((t) => t.id == transactionId);
    } catch (e) {
      return null;
    }
  }

  void dispose() {
    _iapHandler.dispose();
    _transactionController.close();
  }
}

// ==================== Receipt Validator ====================

class ReceiptValidator {
  static Future<bool> validateAppleReceipt(String receiptData) async {
    try {
      final url = Platform.isIOS
          ? 'https://buy.itunes.apple.com/verifyReceipt'
          : 'https://sandbox.itunes.apple.com/verifyReceipt';

      final response = await http.post(
        Uri.parse(url),
        headers: {'Content-Type': 'application/json'},
        body: json.encode({
          'receipt-data': receiptData,
          'password': 'your-shared-secret',
        }),
      );

      if (response.statusCode == 200) {
        final data = json.decode(response.body);
        return data['status'] == 0;
      }

      return false;
    } catch (e) {
      debugPrint('Receipt validation error: $e');
      return false;
    }
  }

  static Future<bool> validateGoogleReceipt(
    String packageName,
    String productId,
    String purchaseToken,
  ) async {
    try {
      final response = await http.get(
        Uri.parse(
          'https://androidpublisher.googleapis.com/androidpublisher/v3/applications/$packageName/purchases/products/$productId/tokens/$purchaseToken',
        ),
        headers: {
          'Authorization': 'Bearer YOUR_ACCESS_TOKEN',
        },
      );

      if (response.statusCode == 200) {
        final data = json.decode(response.body);
        return data['purchaseState'] == 0;
      }

      return false;
    } catch (e) {
      debugPrint('Receipt validation error: $e');
      return false;
    }
  }
}

// ==================== PCI Compliance Utilities ====================

class PCIComplianceUtils {
  static bool validateCardNumber(String cardNumber) {
    final cleaned = cardNumber.replaceAll(RegExp(r'\s+'), '');
    if (cleaned.length < 13 || cleaned.length > 19) return false;

    int sum = 0;
    bool alternate = false;

    for (int i = cleaned.length - 1; i >= 0; i--) {
      int digit = int.parse(cleaned[i]);

      if (alternate) {
        digit *= 2;
        if (digit > 9) digit -= 9;
      }

      sum += digit;
      alternate = !alternate;
    }

    return sum % 10 == 0;
  }

  static String maskCardNumber(String cardNumber) {
    if (cardNumber.length < 4) return '****';
    return '**** **** **** ${cardNumber.substring(cardNumber.length - 4)}';
  }

  static bool validateCVV(String cvv) {
    return RegExp(r'^\d{3,4}$').hasMatch(cvv);
  }

  static bool validateExpiryDate(String expiry) {
    final parts = expiry.split('/');
    if (parts.length != 2) return false;

    final month = int.tryParse(parts[0]);
    final year = int.tryParse(parts[1]);

    if (month == null || year == null) return false;
    if (month < 1 || month > 12) return false;

    final now = DateTime.now();
    final fullYear = year < 100 ? 2000 + year : year;
    final expiryDate = DateTime(fullYear, month + 1, 0);

    return expiryDate.isAfter(now);
  }

  static String sanitizeCardData(String data) {
    return data.replaceAll(RegExp(r'[^\d]'), '');
  }
}

