void main() async {
  final paymentManager = PaymentManager();

  await paymentManager.initialize(
    encryptionKey: 'your-32-character-encryption-key',
    apiKey: 'your-api-key',
    stripePublishableKey: 'pk_test_...',
    stripeSecretKey: 'sk_test_...',
    isProduction: false,
  );

  paymentManager.transactionStream.listen((transaction) {
    print('Transaction: ${transaction.id} - ${transaction.status}');
  });

  final products = await paymentManager.fetchProducts([
    'com.example.product1',
    'com.example.product2',
  ]);

  print('Available products: ${products.length}');

  final result = await paymentManager.processPayment(
    userId: 'user123',
    amount: 9.99,
    currency: 'USD',
    method: PaymentMethod.stripe,
    description: 'Premium subscription',
  );

  if (result.success) {
    print('Payment successful: ${result.transaction?.id}');
  } else {
    print('Payment failed: ${result.errorMessage}');
  }

  final isApplePayAvailable =
      await paymentManager.isPaymentMethodAvailable(PaymentMethod.applePay);
  print('Apple Pay available: $isApplePayAvailable');

  final userTransactions = paymentManager.getTransactionsByUser('user123');
  print('User transactions: ${userTransactions.length}');
}